const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const SRC = path.join(PROJECT, 'src');

const readFile = (p) => {
  try { return fs.readFileSync(p, 'utf8'); } catch { return '// FILE NOT FOUND'; }
};

const context = {
  app: readFile(path.join(SRC, 'App.tsx')),
  antennaForm: readFile(path.join(SRC, 'components/AntennaForm/AntennaForm.tsx')),
  s11Chart: readFile(path.join(SRC, 'components/S11Chart/S11Chart.tsx')),
  viewport: readFile(path.join(SRC, 'viewport/AntennaViewport.tsx')),
  indexCss: readFile(path.join(SRC, 'index.css')),
  uiSpec: readFile(path.join(PROJECT, '.claude/ui-spec.json')),
  bridge: readFile(path.join(PROJECT, 'src-tauri/src/bridge.rs')),
  tsconfig: readFile(path.join(PROJECT, 'tsconfig.json')),
  packageJson: readFile(path.join(PROJECT, 'package.json')),
  stepLoader: readFile(path.join(SRC, 'lib/stepLoader.ts')),
};

return [{ json: { context } }];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';

const agents = ['Gen File Upload', 'Gen Mesh Viewer', 'Gen Solver Panel', 'Gen Progress + Results', 'Gen App Update'];
const fileRegex = /<file path="([^"]+)">\n?([\s\S]*?)<\/file>/g;
const results = {};
let filesWritten = 0;

for (const agentName of agents) {
  try {
    const output = $(agentName).item.json.output || '';
    let match;
    const regex = new RegExp(fileRegex.source, fileRegex.flags);
    while ((match = regex.exec(output)) !== null) {
      const fullPath = path.join(PROJECT, match[1]);
      const dir = path.dirname(fullPath);
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
      fs.writeFileSync(fullPath, match[2].trim());
      results[match[1]] = `WRITTEN (${match[2].length} chars)`;
      filesWritten++;
    }
  } catch (e) {
    results[agentName] = `ERROR: ${e.message}`;
  }
}

let tscResult = '';
try {
  tscResult = execSync('npx tsc --noEmit 2>&1', { cwd: PROJECT, timeout: 120000 }).toString();
  if (!tscResult.trim()) tscResult = 'OK';
} catch (e) {
  tscResult = e.stdout?.toString() || e.message;
}

let buildResult = '';
try {
  buildResult = execSync('npm run build 2>&1', { cwd: PROJECT, timeout: 180000 }).toString();
  buildResult = buildResult.includes('error') ? buildResult : 'OK';
} catch (e) {
  buildResult = e.stdout?.toString() || e.message;
}

return [{ json: { filesWritten, results, tscResult, buildResult } }];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const prev = $('Write + TSC + Build').item.json;
const needsFix = prev.tscResult !== 'OK' || prev.buildResult !== 'OK';
let fixResult = 'No fix needed';

if (needsFix) {
  const output = $('Self-Fix Agent').item.json.output || '';
  const fileRegex = /<file path="([^"]+)">\n?([\s\S]*?)<\/file>/g;
  let match;
  while ((match = fileRegex.exec(output)) !== null) {
    const fullPath = path.join(PROJECT, match[1]);
    const dir = path.dirname(fullPath);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(fullPath, match[2].trim());
  }
  try {
    execSync('npx tsc --noEmit 2>&1', { cwd: PROJECT, timeout: 120000 });
    fixResult = 'TSC OK after fix';
  } catch (e) {
    fixResult = 'Still has TSC errors: ' + (e.stdout?.toString().slice(0, 300) || e.message);
  }
}

let gitResult = '';
try {
  execSync('git add -A', { cwd: PROJECT });
  execSync('git commit -m "feat(ui): add EM solver frontend components\n\nFileImport with drag-drop CAD upload, MeshViewer with R3F,\nSolverPanel with MoM/FDTD selection, progress tracking,\nresults display with S-params and radiation pattern."', { cwd: PROJECT });
  execSync('git push origin main', { cwd: PROJECT });
  gitResult = 'Committed and pushed';
} catch (e) {
  gitResult = 'Git: ' + e.message;
}

return [{ json: { ...prev, fixResult, gitResult, phase: 'frontend', status: 'complete' } }];
